const user = $('Per User').item.json;
const logs = $('Get 7-Day Logs').all().map(i => i.json);
if (!logs.length) return [{ json: { skip: true, telegramId: user.telegram_id } }];
const n = logs.length;
const avg = (fn) => (logs.reduce((s,d) => s + (parseFloat(fn(d))||0), 0) / n);
const avgCal = Math.round(avg(d => d.calories_consumed));
const avgSleep = avg(d => d.sleep_hours).toFixed(1);
const avgEnergy = avg(d => d.energy_level).toFixed(1);
const avgSteps = Math.round(avg(d => d.steps));
const workoutDays = logs.filter(d => d.workout_done).length;
const target = user.daily_calorie_target || 2000;
const onTarget = logs.filter(d => { const c=d.calories_consumed||0; return c>=target*0.85 && c<=target*1.15; }).length;
const adherence = Math.round((onTarget/n)*100);
return [{ json: { skip:false, userId:user.id, telegramId:user.telegram_id, firstName:user.first_name, goal:user.goal, target, n, avgCal, avgSleep, avgEnergy, avgSteps, workoutDays, adherence } }];
